mapper.select:
SELECT sh.shipment_id, sh.so_id, cu.customer_name, so.order_date, sh.shipment_date, sh.shipped_emp_id, em.emp_name as employeeName, sh.memo, sh.created_at, sh.status FROM shipment sh JOIN sales_order so ON so.so_id=sh.so_id JOIN customer cu ON cu.customer_id = so.customer_id JOIN employee em ON em.emp_id = sh.shipped_emp_id
AND sh.so_id=#{salesOrderId}
AND sh.status=UPPER(#{status})
AND em.emp_name=#{employeeName}
ORDER BY sh.shipment_id

SELECT shipment_id, so_id, shipped_emp_id, shipment_date, status, created_at FROM shipment
shipment_id=#{shipmentId}
AND status='SHIPPED'

SELECT sh.shipment_id, sod.so_id, sod.so_detail_id, pr.product_name, il.lot_no, shd.shipment_detail_id, shd.inventory_lot_id, smv.before_qty, smv.after_qty, sh.shipment_date, shd.shipped_qty, smv.qty, smv.created_at, smv.created_by FROM shipment_detail shd JOIN shipment sh ON sh.shipment_id=shd.shipment_id JOIN sales_order_detail sod ON sod.so_detail_id=shd.so_detail_id AND sod.so_id=sh.so_id JOIN product pr ON pr.product_id=sod.product_id JOIN inventory_lot il ON il.inventory_lot_id=shd.inventory_lot_id JOIN stock_movement smv ON smv.source_id=shd.shipment_detail_id AND smv.source_type='SHIPMENT_DETAIL' AND smv.movement_type='OUT'
AND sh.shipment_id=#{shipmentId}
ORDER BY shd.shipment_detail_id

SELECT so.so_id as sales_order_id, sh.shipment_id, sd.shipped_qty, sh.shipment_date, pr.product_id, il.inventory_lot_id, il.lot_no, sm.movement_type, pr.product_name, sm.source_type, sm.before_qty, sm.qty as movement_qty, sm.after_qty FROM shipment sh join sales_order so on so.so_id=sh.so_id join shipment_detail sd on sd.shipment_id=sh.shipment_id join stock_movement sm on sm.source_id=sd.shipment_detail_id join inventory_lot il on il.inventory_lot_id=sd.inventory_lot_id join sales_order_detail sod on sod.so_detail_id=sd.so_detail_id and sod.so_id=so.so_id join product pr on pr.product_id = sod.product_id WHERE sm.movement_type='OUT' AND sm.source_type='SHIPMENT_DETAIL' AND so.status='SHIPPED' AND sh.status='SHIPPED'
AND so.so_id=#{salesOrderId}
ORDER BY so.so_id, sh.shipment_id

SELECT pro.product_id, pro.product_name, il.inventory_lot_id, il.lot_no,
shd.shipment_id,
rc.receiving_id,
smv.movement_id, smv.movement_type, smv.source_type, smv.source_id, smv.before_qty, smv.qty, smv.after_qty, smv.created_at FROM stock_movement smv JOIN inventory_lot il ON il.inventory_lot_id = smv.inventory_lot_id JOIN product pro ON pro.product_id=il.product_id
LEFT JOIN shipment_detail shd ON smv.source_type='SHIPMENT_DETAIL' AND smv.source_id=shd.shipment_detail_id
LEFT JOIN receiving rc ON smv.source_type='RECEIVING' AND smv.source_id=rc.receiving_id
AND pro.product_name=#{productName}
AND il.lot_no=#{lotNo}
AND smv.source_type=#{sourceType}
AND smv.source_id=#{sourceId}
AND shd.shipment_id=#{shipmentId}
AND rc.receiving_id=#{receivingId}
AND smv.created_at >= #{startDate}
AND smv.created_at <= #{endDate}
ORDER BY smv.created_at DESC
